// image-slideshow.ts - VERSIONE CON TRANSIZIONE FLUIDA
import { Component, Input, OnInit, OnDestroy, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-image-slideshow',
  templateUrl: './image-slideshow.html',
  styleUrls: ['./image-slideshow.css'],
  imports: [CommonModule]
})
export class ImageSlideshow implements OnInit, OnDestroy {
  @Input() images: string[] = [];
  @Input() autoPlay = true;
  @Input() interval = 3000;
  @Input() transitionDuration = 600; // Durata transizione in ms
  @Output() imageClicked = new EventEmitter<number>();

  currentIndex = 0;
  previousIndex = 0;
  isTransitioning = false;
  direction: 'next' | 'prev' = 'next';
  private timer: any;

  ngOnInit() {
    if (this.autoPlay && this.images.length > 0) {
      this.startAutoPlay();
    }
  }

  ngOnDestroy() {
    this.stopAutoPlay();
  }

  startAutoPlay() {
    if (this.timer) {
      clearInterval(this.timer);
    }
    
    if (this.images.length > 0 && this.autoPlay) {
      this.timer = setInterval(() => {
        this.next();
      }, this.interval);
    }
  }

  stopAutoPlay() {
    if (this.timer) {
      clearInterval(this.timer);
      this.timer = null;
    }
  }

  next() {
    if (this.images.length === 0 || this.isTransitioning) return;
    
    this.direction = 'next';
    this.previousIndex = this.currentIndex;
    this.currentIndex = (this.currentIndex + 1) % this.images.length;
    this.startTransition();
  }

  prev() {
    if (this.images.length === 0 || this.isTransitioning) return;
    
    this.direction = 'prev';
    this.previousIndex = this.currentIndex;
    this.currentIndex = (this.currentIndex - 1 + this.images.length) % this.images.length;
    this.startTransition();
  }

  goTo(index: number) {
    if (this.images.length === 0 || this.isTransitioning || index === this.currentIndex) return;
    
    this.direction = index > this.currentIndex ? 'next' : 'prev';
    this.previousIndex = this.currentIndex;
    this.currentIndex = index;
    this.startTransition();
  }

  private startTransition() {
    this.isTransitioning = true;
    
    // Finisce la transizione dopo la durata specificata
    setTimeout(() => {
      this.isTransitioning = false;
    }, this.transitionDuration);
  }

  onImageError(event: Event) {
    const img = event.target as HTMLImageElement;
    console.error('Errore caricamento immagine:', img.src);
    img.style.display = 'none';
    
    const index = this.images.indexOf(img.src);
    if (index > -1) {
      this.images.splice(index, 1);
    }
    
    if (this.images.length === 0) {
      this.stopAutoPlay();
      return;
    }
    
    if (this.currentIndex >= this.images.length) {
      this.currentIndex = 0;
    }
  }

onImageClick(index: number) {
    console.log('Cliccata immagine n°', index); // per debug
    this.imageClicked.emit(index);               // emette al genitore
  }  
}